// String literal — no curly braces needed
<Avatar name="Alice" />

// Number — curly braces required
<Avatar size={48} />

// Boolean — curly braces required
<Avatar isOnline={true} />

// Boolean shorthand — attribute alone means true
<Avatar isOnline />       // same as isOnline={true}

// Variable or expression — always needs curly braces
<Avatar name={user.name} size={AVATAR_SIZE * 2} />

// Object
<Avatar style={{ borderRadius: '50%' }} />

// Array
<Avatar badges={['admin', 'verified']} />

// Function
<Avatar onClick={() => console.log('clicked')} />

// Option 1: receive the props object
function Avatar(props) {
  return (
    <img
      src={props.avatarUrl}
      alt={props.name}
      width={props.size}
    />
  );
}

// Option 2: destructure in the parameter (preferred)
function Avatar({ avatarUrl, name, size }) {
  return <img src={avatarUrl} alt={name} width={size} />;
}

function Avatar({ name, size = 48, isOnline = false }) {
  return (
    <div style={{ position: 'relative', width: size, height: size }}>
      <img src={`/avatars/${name}.jpg`} alt={name} width={size} />
      {isOnline && <span className="online-dot" />}
    </div>
  );
}

// size defaults to 48; isOnline defaults to false
<Avatar name="Alice" />

// Overrides the default
<Avatar name="Bob" size={64} isOnline />

// Rename 'size' to 'avatarSize' internally
function Avatar({ avatarUrl, name, size: avatarSize = 48 }) {
  return <img src={avatarUrl} alt={name} width={avatarSize} />;
}

// Rename 'class' received from a data API to 'className'
function UserBadge({ label, class: badgeClass }) {
  return <span className={badgeClass}>{label}</span>;
}

function PrimaryButton({ className, children, ...rest }) {
  return (
    <button
      className={`btn-primary ${className ?? ''}`}
      {...rest}
    >
      {children}
    </button>
  );
}

// All these reach the underlying <button>
<PrimaryButton onClick={save} disabled={isSaving} type="submit">
  Save
</PrimaryButton>

// BAD — never mutate props
function Counter({ count }) {
  count += 1;   // ← has no effect on the parent; React does not see this
  return <p>{count}</p>;
}

// GOOD — derive a new value, or lift state up to the parent
function Counter({ count }) {
  const displayCount = count + 1;   // local derivation, not mutation
  return <p>{displayCount}</p>;
}

function Card({ children, title }) {
  return (
    <section className="card">
      <h2>{title}</h2>
      <div className="card-body">{children}</div>
    </section>
  );
}

<Card title="Profile">
  <Avatar name="Alice" />
  <p>Alice is an admin.</p>
</Card>

function Dialog({ title, body, footer }) {
  return (
    <div className="dialog">
      <header>{title}</header>
      <main>{body}</main>
      <footer>{footer}</footer>
    </div>
  );
}

<Dialog
  title={<h2>Confirm Delete</h2>}
  body={<p>This action cannot be undone.</p>}
  footer={
    <>
      <button onClick={onCancel}>Cancel</button>
      <button onClick={onConfirm}>Delete</button>
    </>
  }
/>

// Readable nested destructure
function UserCard({ user: { name, email, avatar } }) {
  return (
    <div>
      <img src={avatar} alt={name} />
      <p>{name}</p>
      <p>{email}</p>
    </div>
  );
}

// Prefer flat props when possible — easier to understand at a glance
function UserCard({ name, email, avatarUrl }) {
  return (
    <div>
      <img src={avatarUrl} alt={name} />
      <p>{name}</p>
      <p>{email}</p>
    </div>
  );
}

import PropTypes from 'prop-types';

function Avatar({ name, size, isOnline }) {
  return <img src={`/avatars/${name}.jpg`} alt={name} width={size} />;
}

Avatar.propTypes = {
  name:     PropTypes.string.isRequired,
  size:     PropTypes.number,
  isOnline: PropTypes.bool,
};

Avatar.defaultProps = {
  size:     48,
  isOnline: false,
};

interface AvatarProps {
  name: string;
  size?: number;      // optional, has a default
  isOnline?: boolean;
}

function Avatar({ name, size = 48, isOnline = false }: AvatarProps) {
  return (
    <div>
      <img src={`/avatars/${name}.jpg`} alt={name} width={size} />
      {isOnline && <span className="dot" />}
    </div>
  );
}

// --- ProductCard.jsx ---
function ProductCard({
  name,
  price,
  imageUrl,
  category,
  inStock = true,
  onAddToCart,
}) {
  return (
    <article className="product-card">
      <img src={imageUrl} alt={name} />
      <span className="badge">{category}</span>
      <h3>{name}</h3>
      <p>${price.toFixed(2)}</p>
      <button
        onClick={() => onAddToCart(name)}
        disabled={!inStock}
      >
        {inStock ? 'Add to cart' : 'Out of stock'}
      </button>
    </article>
  );
}

// --- ProductList.jsx ---
const PRODUCTS = [
  { id: 1, name: 'Widget', price: 9.99, imageUrl: '/w.jpg', category: 'tools', inStock: true },
  { id: 2, name: 'Gadget', price: 24.99, imageUrl: '/g.jpg', category: 'tech',  inStock: false },
];

function ProductList() {
  function handleAddToCart(productName) {
    console.log('Adding to cart:', productName);
  }

  return (
    <div className="grid">
      {PRODUCTS.map(product => (
        <ProductCard
          key={product.id}
          name={product.name}
          price={product.price}
          imageUrl={product.imageUrl}
          category={product.category}
          inStock={product.inStock}
          onAddToCart={handleAddToCart}
        />
      ))}
    </div>
  );
}

function Input({ label, id, className, ...inputProps }) {
  return (
    <div className="field">
      <label htmlFor={id}>{label}</label>
      <input
        id={id}
        className={`input ${className ?? ''}`}
        {...inputProps}        // forwards type, value, onChange, placeholder, etc.
      />
    </div>
  );
}

<Input
  label="Email"
  id="email"
  type="email"
  placeholder="you@example.com"
  value={email}
  onChange={e => setEmail(e.target.value)}
/>

// BAD — derived data passed as extra props
<Badge status="active" label="Active" colour="green" />

// GOOD — derive label and colour from the single status prop
const STATUS_META = {
  active:   { label: 'Active',   colour: 'green' },
  inactive: { label: 'Inactive', colour: 'gray' },
  banned:   { label: 'Banned',   colour: 'red' },
};

function Badge({ status }) {
  const { label, colour } = STATUS_META[status];
  return <span className={`badge badge-${colour}`}>{label}</span>;
}

<Badge status="active" />

function RangeSlider({ min, max, value, onChange }) {
  return (
    <input
      type="range"
      min={min}
      max={max}
      value={value}
      onChange={e => onChange(Number(e.target.value))}  // pass plain number, not the event
    />
  );
}

// Caller receives a number directly, not a DOM event:
<RangeSlider
  min={0} max={100}
  value={volume}
  onChange={setVolume}
/>
